INSERT INTO admin_audit_logs (
    id, operator_id, operator_name, role_code,
    action, resource_type, resource_id, result,
    ip, user_agent, request_id, error_message, occurred_at
) VALUES (
    #{id}, #{operatorId}, #{operatorName}, #{roleCode},
    #{action}, #{resourceType}, #{resourceId}, #{result},
    #{ip}, #{userAgent}, #{requestId}, #{errorMessage}, #{occurredAt}
)

mapper.select:
SELECT *
FROM admin_audit_logs


        AND action = #{action}


        AND operator_id = #{operatorId}


        AND resource_type = #{resourceType}


        AND resource_id = #{resourceId}


        AND occurred_at >= #{from}


        AND occurred_at <= #{to}


ORDER BY occurred_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM admin_audit_logs


        AND action = #{action}


        AND operator_id = #{operatorId}


        AND resource_type = #{resourceType}


        AND resource_id = #{resourceId}


        AND occurred_at >= #{from}


        AND occurred_at <= #{to}

SELECT operator_id, MAX(operator_name) AS operator_name, MAX(occurred_at) AS occurred_at FROM admin_audit_logs
AND operator_id IS NOT NULL AND operator_id != ''
AND occurred_at >= #{from}
AND occurred_at <= #{to}
AND ( operator_id LIKE CONCAT('%', #{operatorKeyword}, '%') OR operator_name LIKE CONCAT('%', #{operatorKeyword}, '%') )
GROUP BY operator_id ORDER BY MAX(occurred_at) DESC LIMIT #{limit}

SELECT action
FROM admin_audit_logs

    AND action IS NOT NULL
    AND action != ''

        AND occurred_at >= #{from}


        AND occurred_at <= #{to}


GROUP BY action
ORDER BY MAX(occurred_at) DESC
LIMIT #{limit}

SELECT resource_type
FROM admin_audit_logs

    AND resource_type IS NOT NULL
    AND resource_type != ''

        AND occurred_at >= #{from}


        AND occurred_at <= #{to}


GROUP BY resource_type
ORDER BY MAX(occurred_at) DESC
LIMIT #{limit}
